     4|/**
     5| * Safe runtime-environment detection for the IVX owner-proof flow.
     6| *
     7| * This NEVER weakens the production admin guard. It only reports *where* the app
     8| * is currently running so the Code Developer Workspace can surface the owner
     9| * build-marker proof flow inside Expo Go / a dev client, while leaving every
    10| * server-side authorization gate exactly as-is.
    11| */
    12|
    13|export type IVXRuntimeKind = 'expo-go' | 'dev-client' | 'standalone' | 'web' | 'unknown';
    14|
    15|export interface IVXRuntimeInfo {
    16|  kind: IVXRuntimeKind;
    17|  /** True when running inside the Expo Go sandbox app. */
    18|  isExpoGo: boolean;
    19|  /** True for any development runtime (Expo Go, dev client, or __DEV__ bundle). */
    20|  isDevRuntime: boolean;
    21|  /** True when this is a shipped production build (App Store / TestFlight / store). */
    22|  isStandalone: boolean;
    23|  isWeb: boolean;
    24|}
    25|
    26|/**
    27| * Resolves the current runtime without throwing. Uses expo-constants
    28| * `executionEnvironment` / `appOwnership`, falling back to `__DEV__` and the
    29| * Platform so it is always safe to call from any screen.
    30| */
    31|export function getIVXRuntimeInfo(): IVXRuntimeInfo {
    32|  const isWeb = Platform.OS === 'web';
    33|
    34|  // executionEnvironment: 'storeClient' (Expo Go), 'standalone' (EAS store build),
    35|  // 'bare' (prebuilt / bare workflow). A bare workflow release APK is a real
    36|  // production build, not a dev client; only flag it as a dev runtime when
    37|  // React Native's __DEV__ flag is true.
    38|  const executionEnvironment = String(Constants.executionEnvironment ?? '');
    39|  // appOwnership: 'expo' (Expo Go), 'standalone', 'guest' (dev client / bare).
    40|  const appOwnership = String(Constants.appOwnership ?? '');
    41|
    42|  const isExpoGo =
    43|    executionEnvironment === 'storeClient' || appOwnership === 'expo';
    44|  const isBare = executionEnvironment === 'bare' || appOwnership === 'guest';
    45|  const devFlag = typeof __DEV__ !== 'undefined' && __DEV__ === true;
    46|  // A bare workflow build is standalone/production when it is a release bundle.
    47|  const isStandalone =
    48|    executionEnvironment === 'standalone' || appOwnership === 'standalone' || (isBare && !devFlag);
    49|  const isDevClient = isBare && devFlag;
    50|
    51|  let kind: IVXRuntimeKind = 'unknown';
    52|  if (isWeb) {
    53|    kind = 'web';
    54|  } else if (isExpoGo) {
    55|    kind = 'expo-go';
    56|  } else if (isStandalone) {
    57|    kind = 'standalone';
    58|  } else if (isDevClient) {
    59|    kind = 'dev-client';
    60|  }
    61|
    62|  return {
    63|    kind,
    64|    isExpoGo,
    65|    isDevRuntime: isExpoGo || isDevClient || devFlag,
    66|    isStandalone,
    67|    isWeb,
    68|  };
    69|}
    70|
    71|/** Convenience: true when the owner-proof flow may be surfaced in this runtime. */
    72|export function isOwnerProofRuntimeAllowed(): boolean {
    73|  const info = getIVXRuntimeInfo();
    74|  // Allow in Expo Go, dev clients, and any dev runtime. Standalone production
    75|  // builds still reach the flow only through the unchanged admin guard.
    76|  return info.isDevRuntime || info.isStandalone || info.isWeb;
